package com.example.bankingapp;

import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {
    private TextView balanceDisplay;
    private EditText transactionInput;
    private Button processButton;
    private double currentBalance = 0.0; // Initialize with zero balance

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        balanceDisplay = findViewById(R.id.balanceDisplay);
        transactionInput = findViewById(R.id.transactionInput);
        processButton = findViewById(R.id.processButton);

        // Set initial display of balance
        updateBalanceDisplay();

        processButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                handleTransaction();
            }
        });
    }

    private void handleTransaction() {
        String input = transactionInput.getText().toString();
        if (input.isEmpty()) return; // Ignore empty inputs
        
        double amount = Double.parseDouble(input);
        currentBalance += amount;

        updateBalanceDisplay();
    }

    private void updateBalanceDisplay() {
        balanceDisplay.setText("Current Balance: $" + String.format("%.2f", currentBalance));
    }
}